document.addEventListener("DOMContentLoaded",()=>{const o={threshold:.1,rootMargin:"0px 0px -50px 0px"},n=new IntersectionObserver(e=>{e.forEach(t=>{t.isIntersecting&&(t.target.classList.add("animate-in"),n.unobserve(t.target))})},o);document.querySelectorAll("section").forEach((e,t)=>{t===0&&e.getBoundingClientRect().top<200||(e.classList.add("fade-in-section"),n.observe(e))})});
